// src/otel-backend-setup.js
//
// OpenTelemetry SDK initialization for code-server backend
// Sets up automatic instrumentation for Express, HTTP, database, and cache operations
//
// Generated by: Phase 3 observability spine - TASK 6 (Backend Instrumentation)

const { BasicTracerProvider, ConsoleSpanExporter, SimpleSpanProcessor } = require('@opentelemetry/sdk-node');
const { getNodeAutoInstrumentations } = require('@opentelemetry/auto-instrumentations-node');
const { OTLPTraceExporter } = require('@opentelemetry/exporter-trace-otlp-http');
const { Resource } = require('@opentelemetry/resources');
const { SemanticResourceAttributes } = require('@opentelemetry/semantic-conventions');
const { registerInstrumentations } = require('@opentelemetry/instrumentation');
const { HttpInstrumentation } = require('@opentelemetry/instrumentation-http');
const { ExpressInstrumentation } = require('@opentelemetry/instrumentation-express');
const { PgInstrumentation } = require('@opentelemetry/instrumentation-pg');
const { RedisInstrumentation } = require('@opentelemetry/instrumentation-redis');
const { trace, context, propagation } = require('@opentelemetry/api');
const { W3CTraceContextPropagator } = require('@opentelemetry/core');

/**
 * Initialize OpenTelemetry for the code-server backend
 * Must be called BEFORE any application code runs (in server.js before imports)
 */
function initOTelBackend() {
  const environment = process.env.NODE_ENV || 'development';
  const isProduction = environment === 'production';
  const otelEndpoint = process.env.OTEL_EXPORTER_OTLP_ENDPOINT || 'http://localhost:4318';
  const serviceName = process.env.OTEL_SERVICE_NAME || 'code-server-backend';
  const serviceVersion = process.env.OTEL_SERVICE_VERSION || '0.1.0';
  const samplingRate = environment === 'production' ? 0.01 : environment === 'staging' ? 0.1 : 1.0;

  // Create resource with metadata
  const resource = Resource.default().merge(
    new Resource({
      [SemanticResourceAttributes.SERVICE_NAME]: serviceName,
      [SemanticResourceAttributes.SERVICE_VERSION]: serviceVersion,
      [SemanticResourceAttributes.SERVICE_NAMESPACE]: 'production',
      [SemanticResourceAttributes.DEPLOYMENT_ENVIRONMENT]: environment,
    })
  );

  // Create trace provider
  const tracerProvider = new BasicTracerProvider({ resource });

  // Export spans to OTLP backend
  const otlpExporter = new OTLPTraceExporter({
    url: `${otelEndpoint}/v1/traces`,
    headers: {
      'Content-Type': 'application/json',
    },
  });

  // Add OTLP exporter to span processor
  tracerProvider.addSpanProcessor(new SimpleSpanProcessor(otlpExporter));

  // For development, also log to console
  if (!isProduction) {
    const consoleExporter = new ConsoleSpanExporter();
    tracerProvider.addSpanProcessor(new SimpleSpanProcessor(consoleExporter));
  }

  // Set global tracer provider
  trace.setGlobalTracerProvider(tracerProvider);

  // Set propagation format (W3C Trace Context)
  propagation.setGlobalPropagator(new W3CTraceContextPropagator());

  // Register automatic instrumentations
  registerInstrumentations({
    instrumentations: [
      // HTTP instrumentation (incoming requests)
      new HttpInstrumentation({
        requestHook: (span, request) => {
          span.setAttributes({
            'http.method': request.method,
            'http.url': request.url,
            'http.user_agent': request.headers['user-agent'] || 'unknown',
          });
        },

        responseHook: (span, response) => {
          span.setAttributes({
            'http.status_code': response.statusCode,
          });
        },

        // Don't trace health checks
        ignoreIncomingRequestHook: (request) => {
          return request.url && (request.url.includes('/health') || request.url.includes('/healthz'));
        },
      }),

      // Express instrumentation
      new ExpressInstrumentation({
        requestHook: (span, req) => {
          // Add custom attributes to Express spans
          span.setAttributes({
            'express.route': req.route?.path || req.path,
            'express.method': req.method,
            'user.id': req.user?.id || 'anonymous',
            'session.id': req.sessionID || 'none',
          });
        },

        responseHook: (span, response) => {
          span.setAttributes({
            'http.status_code': response.statusCode,
          });
        },
      }),

      // PostgreSQL instrumentation
      new PgInstrumentation({
        responseHook: (span, queryResult) => {
          // Add query result metadata
          if (queryResult && queryResult.rows) {
            span.setAttributes({
              'db.rows_affected': queryResult.rows.length || 0,
            });
          }
        },

        // Sanitize sensitive query data
        sqlParameterValues: [],  // Don't log parameter values to prevent leaking secrets
      }),

      // Redis instrumentation
      new RedisInstrumentation({
        // Redis command hook
        responseHook: (span, cmdArgs) => {
          if (cmdArgs && cmdArgs[0]) {
            span.setAttributes({
              'redis.command': cmdArgs[0].toUpperCase() || 'unknown',
            });
          }
        },
      }),
    ],
  });

  // Log initialization in development
  if (!isProduction) {
    console.log(`[OTEL] Backend initialized for ${environment} environment`);
    console.log(`[OTEL] Service: ${serviceName} v${serviceVersion}`);
    console.log(`[OTEL] Sampling rate: ${samplingRate}`);
    console.log(`[OTEL] Backend: ${otelEndpoint}`);
  }

  return trace.getTracer(serviceName);
}

/**
 * Express middleware to inject trace context into responses
 */
function createTraceContextMiddleware() {
  return (req, res, next) => {
    const span = trace.getActiveSpan();
    
    if (span) {
      const spanContext = span.spanContext();
      
      // Add trace context headers to response
      res.setHeader('X-Trace-ID', spanContext.traceId);
      res.setHeader('X-Span-ID', spanContext.spanId);
      res.setHeader('X-Trace-Flags', spanContext.traceFlags);
      
      // Store in request for application access
      req.traceId = spanContext.traceId;
      req.spanId = spanContext.spanId;
    }
    
    next();
  };
}

/**
 * Express middleware to handle trace context propagation from incoming requests
 */
function createTraceContextPropagationMiddleware() {
  return (req, res, next) => {
    // Extract trace context from headers
    const traceparent = req.headers.traceparent || req.headers['x-trace-id'];
    const tracestate = req.headers.tracestate;
    
    // If present, store for logging
    if (traceparent) {
      req.incomingTraceContext = {
        traceparent,
        tracestate: tracestate || '',
      };
    }
    
    next();
  };
}

/**
 * Utility to start a span for a specific operation
 */
function createSpan(operationName, attributes = {}) {
  const tracer = trace.getTracer('code-server-backend');
  
  return tracer.startActiveSpan(operationName, (span) => {
    // Set attributes
    Object.entries(attributes).forEach(([key, value]) => {
      span.setAttributes({ [key]: value });
    });
    
    return span;
  });
}

/**
 * Utility to execute a function within a span context
 */
async function withSpan(operationName, fn, attributes = {}) {
  const tracer = trace.getTracer('code-server-backend');
  
  return tracer.startActiveSpan(operationName, async (span) => {
    try {
      // Set attributes
      Object.entries(attributes).forEach(([key, value]) => {
        span.setAttributes({ [key]: value });
      });
      
      // Execute function
      const result = await fn(span);
      
      // Mark success
      span.setAttributes({ 'operation.success': true });
      
      return result;
    } catch (error) {
      // Record error
      span.recordException(error);
      span.setAttributes({
        'operation.success': false,
        'error.type': error.name || 'Unknown',
        'error.message': error.message || 'Unknown error',
      });
      
      throw error;
    }
  });
}

/**
 * Get current trace ID from active span
 */
function getCurrentTraceId() {
  const span = trace.getActiveSpan();
  return span ? span.spanContext().traceId : null;
}

/**
 * Get current span ID from active span
 */
function getCurrentSpanId() {
  const span = trace.getActiveSpan();
  return span ? span.spanContext().spanId : null;
}

module.exports = {
  initOTelBackend,
  createTraceContextMiddleware,
  createTraceContextPropagationMiddleware,
  createSpan,
  withSpan,
  getCurrentTraceId,
  getCurrentSpanId,
  trace,
  context,
};
